"use client";

import React, { useState, useMemo, useRef, useEffect } from "react";
import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import { generateLayout, type PositionedName } from "./layoutEngine";
import { BackgroundLayer } from "./BackgroundLayer";
import { NameItem } from "./NameItem";

export interface NamesLandingProps {
  names: string[];
  variant?: "constellation" | "grid" | "helical";
  title?: string;
  subtitle?: string;
  background?: "solid" | "noise" | "paper" | "grid" | "gradient" | "texture";
  density?: number; // 1 (Sparse), 2 (Balanced), 3 (Dense)
  spacing?: number; // Spacing scaling multiplier (default: 1.0)
  fontFamily?: "sans" | "mono" | "grotesk" | "serif" | "suisse";
  fontWeight?: number;
  fontScale?: number; // Overall text size scaling factor
  rotation?: number; // Maximum rotation angle (ignored here as layoutEngine handles standard random rotation ranges)
  animationSpeed?: number;
  hoverScale?: number;
  hoverBrightness?: number;
  mouseParallax?: boolean;
  depth?: number; // Number of visual depth layers (default: 3)
  noise?: boolean;
  grid?: boolean;
  showSearch?: boolean;
  highlightedNames?: string[];
  colorMode?: "light" | "dark";
  className?: string;
  renderName?: (
    name: string,
    index: number,
    state: { isHovered: boolean; isHighlighted: boolean; isMatched: boolean }
  ) => React.ReactNode;
}

export function NamesLanding({
  names = [],
  variant = "constellation",
  title,
  subtitle,
  background = "solid",
  density = 2,
  spacing = 1.0,
  fontFamily = "sans",
  fontWeight,
  fontScale = 1.0,
  hoverScale = 1.08,
  hoverBrightness = 1.15,
  mouseParallax = true,
  showSearch = true,
  highlightedNames = [],
  colorMode = "dark",
  className = "",
  renderName
}: NamesLandingProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 1200, height: 800 });
  const [searchQuery, setSearchQuery] = useState("");

  const isDark = colorMode === "dark";

  // 1. Monitor viewport dimensions for real-time recalculation of layout positioning
  useEffect(() => {
    if (!containerRef.current) return;
    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setDimensions({
          width: Math.max(800, entry.contentRect.width),
          height: Math.max(600, entry.contentRect.height)
        });
      }
    });
    resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, []);

  // 2. Compute positions using the layoutEngine
  const items = useMemo(() => {
    return generateLayout(
      names,
      variant,
      dimensions.width,
      dimensions.height,
      density,
      spacing,
      fontScale,
      highlightedNames
    );
  }, [names, variant, dimensions, density, spacing, fontScale, highlightedNames]);

  // 3. Mouse Parallax Coordinate Springs
  const mouseXRaw = useMotionValue(dimensions.width / 2);
  const mouseYRaw = useMotionValue(dimensions.height / 2);

  const springConfig = { stiffness: 75, damping: 22, mass: 0.8 };
  const mouseX = useSpring(mouseXRaw, springConfig);
  const mouseY = useSpring(mouseYRaw, springConfig);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    mouseXRaw.set(x);
    mouseYRaw.set(y);
  };

  // Parallax offsets per layer:
  // Foreground (layer 0): shifts opposite to mouse for maximum parallax effect
  const fgX = useTransform(mouseX, [0, dimensions.width], [22, -22]);
  const fgY = useTransform(mouseY, [0, dimensions.height], [22, -22]);

  // Midground (layer 1): moderate shift
  const mgX = useTransform(mouseX, [0, dimensions.width], [10, -10]);
  const mgY = useTransform(mouseY, [0, dimensions.height], [10, -10]);

  // Background (layer 2): minimal shift
  const bgX = useTransform(mouseX, [0, dimensions.width], [4, -4]);
  const bgY = useTransform(mouseY, [0, dimensions.height], [4, -4]);

  // Soft cursor light follow coordinates
  const cursorLightX = useTransform(mouseX, (x) => x - 225);
  const cursorLightY = useTransform(mouseY, (y) => y - 225);

  // 4. Filtering match lists based on search input
  const searchActive = searchQuery.trim().length > 0;
  const lowercaseQuery = searchQuery.toLowerCase();

  const matchedIds = useMemo(() => {
    if (!searchActive) return new Set<string>();
    const matched = new Set<string>();
    for (const item of items) {
      if (item.name.toLowerCase().includes(lowercaseQuery)) {
        matched.add(item.id);
      }
    }
    return matched;
  }, [items, searchActive, lowercaseQuery]);

  // Group items by depth layer for rendering containment
  const layers = useMemo(() => {
    const l0: PositionedName[] = [];
    const l1: PositionedName[] = [];
    const l2: PositionedName[] = [];

    for (const item of items) {
      if (item.z === 0) l0.push(item);
      else if (item.z === 1) l1.push(item);
      else l2.push(item);
    }
    return { foreground: l0, midground: l1, background: l2 };
  }, [items]);

  // Layout-specific styling mapping
  const overlayTitleStyles = isDark ? "text-white/6" : "text-black/5";

  return (
    <div
      ref={containerRef}
      onMouseMove={handleMouseMove}
      className={`relative w-full h-full overflow-hidden select-none select-none z-10 flex flex-col items-center justify-between p-8 ${className}`}
    >
      {/* Background layer */}
      <BackgroundLayer type={background} colorMode={colorMode} />

      {/* Floating dynamic cursor spotlight lighting */}
      {mouseParallax && !searchActive && (
        <motion.div
          className={`absolute pointer-events-none z-[12] w-[450px] h-[450px] rounded-full blur-[110px] opacity-[0.26] ${
            isDark ? "bg-white" : "bg-neutral-500"
          }`}
          style={{
            x: cursorLightX,
            y: cursorLightY,
            willChange: "transform"
          }}
        />
      )}

      {/* Static / background exhibition details */}
      {(title || subtitle) && (
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none select-none z-5">
          {title && (
            <h1 className={`text-[8.5vw] font-black tracking-[0.08em] uppercase ${overlayTitleStyles} font-sans leading-none text-center select-none`}>
              {title}
            </h1>
          )}
          {subtitle && (
            <p className={`mt-4 font-mono text-xs uppercase tracking-[0.24em] ${isDark ? "text-neutral-600" : "text-neutral-400"}`}>
              {subtitle}
            </p>
          )}
        </div>
      )}

      {/* Search Input Bar Overlay */}
      {showSearch && (
        <div className="relative w-full max-w-xs z-[60] flex flex-col items-center shrink-0">
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="FILTER CATALOGUE..."
            className={`w-full px-4 py-2 font-mono text-[10px] uppercase tracking-wider rounded-xl border outline-none text-center transition-all ${
              isDark 
                ? "bg-[#090909]/60 border-white/8 text-white placeholder-white/25 focus:border-white/20 focus:bg-[#090909]/85"
                : "bg-white/60 border-black/8 text-neutral-900 placeholder-black/25 focus:border-black/20 focus:bg-white/85"
            }`}
          />
        </div>
      )}

      {/* Main Interactive Canvas Area */}
      <div className="absolute inset-0 z-20 pointer-events-none">

        {/* Layer 2: Background items */}
        <motion.div 
          className="absolute inset-0 pointer-events-none" 
          style={{ x: bgX, y: bgY, willChange: "transform" }}
        >
          {layers.background.map((item) => (
            <NameItem
              key={item.id}
              item={item}
              mouseX={mouseXRaw}
              mouseY={mouseYRaw}
              hoverScale={hoverScale}
              hoverBrightness={hoverBrightness}
              isMatched={matchedIds.has(item.id)}
              searchActive={searchActive}
              colorMode={colorMode}
              fontFamily={fontFamily}
              fontWeight={fontWeight}
              mouseParallax={mouseParallax}
              renderName={renderName}
            />
          ))}
        </motion.div>

        {/* Layer 1: Midground items */}
        <motion.div 
          className="absolute inset-0 pointer-events-none" 
          style={{ x: mgX, y: mgY, willChange: "transform" }}
        >
          {layers.midground.map((item) => (
            <NameItem
              key={item.id}
              item={item}
              mouseX={mouseXRaw}
              mouseY={mouseYRaw}
              hoverScale={hoverScale}
              hoverBrightness={hoverBrightness}
              isMatched={matchedIds.has(item.id)}
              searchActive={searchActive}
              colorMode={colorMode}
              fontFamily={fontFamily}
              fontWeight={fontWeight}
              mouseParallax={mouseParallax}
              renderName={renderName}
            />
          ))}
        </motion.div>

        {/* Layer 0: Foreground items */}
        <motion.div 
          className="absolute inset-0 pointer-events-none" 
          style={{ x: fgX, y: fgY, willChange: "transform" }}
        >
          {layers.foreground.map((item) => (
            <NameItem
              key={item.id}
              item={item}
              mouseX={mouseXRaw}
              mouseY={mouseYRaw}
              hoverScale={hoverScale}
              hoverBrightness={hoverBrightness}
              isMatched={matchedIds.has(item.id)}
              searchActive={searchActive}
              colorMode={colorMode}
              fontFamily={fontFamily}
              fontWeight={fontWeight}
              mouseParallax={mouseParallax}
              renderName={renderName}
            />
          ))}
        </motion.div>
      </div>

      {/* Bottom informational meta tags */}
      <div className="relative w-full flex items-center justify-between z-40 text-[9px] font-mono tracking-widest text-neutral-500 uppercase select-none pointer-events-none shrink-0 mt-auto pt-4">
        <div>CATALOG SIZE: {names.length} ITEMS</div>
        <div>RENDER MODE: {variant}</div>
      </div>
    </div>
  );
}

import React, { useState } from "react";
import { motion, useTransform, type MotionValue } from "framer-motion";
import type { PositionedName } from "./layoutEngine";

interface NameItemProps {
  item: PositionedName;
  mouseX: MotionValue<number>;
  mouseY: MotionValue<number>;
  hoverScale: number;
  hoverBrightness: number;
  isMatched: boolean;
  searchActive: boolean;
  colorMode: "light" | "dark";
  fontFamily: "sans" | "mono" | "grotesk" | "serif" | "suisse";
  fontWeight?: number;
  mouseParallax: boolean;
  renderName?: (
    name: string,
    index: number,
    state: { isHovered: boolean; isHighlighted: boolean; isMatched: boolean }
  ) => React.ReactNode;
}

export function NameItem({
  item,
  mouseX,
  mouseY,
  hoverScale = 1.08,
  hoverBrightness = 1.15,
  isMatched,
  searchActive,
  colorMode,
  fontFamily,
  fontWeight,
  mouseParallax,
  renderName
}: NameItemProps) {
  const [isHovered, setIsHovered] = useState(false);
  const isDark = colorMode === "dark";

  // 1. Set font stack classes
  let fontClass = "font-sans";
  const inlineStyles: React.CSSProperties = {};

  if (fontFamily === "mono") {
    fontClass = "font-mono";
  } else if (fontFamily === "serif") {
    fontClass = "font-serif";
  } else if (fontFamily === "grotesk") {
    inlineStyles.fontFamily = "'Space Grotesk', sans-serif";
  } else if (fontFamily === "suisse") {
    inlineStyles.fontFamily = "'Suisse Int\\'l', 'Suisse', 'Inter', sans-serif";
  }

  // 2. Compute text colors based on colorMode, highlighting, and search query match state
  const getColors = () => {
    if (searchActive) {
      if (isMatched) {
        return isDark ? "text-white drop-shadow-[0_0_12px_rgba(255,255,255,0.4)]" : "text-neutral-900 font-bold";
      }
      return isDark ? "text-neutral-800 opacity-15" : "text-neutral-300 opacity-15";
    }

    if (item.isHighlighted) {
      return isDark ? "text-white" : "text-neutral-900";
    }

    // Default layered opacity colors
    if (item.z === 0) return isDark ? "text-neutral-100" : "text-neutral-800";
    if (item.z === 1) return isDark ? "text-neutral-400" : "text-neutral-600";
    return isDark ? "text-neutral-600" : "text-neutral-400";
  };

  // 3. Cursor dynamic lighting - calculate distance from mouse using motion values
  // We use 300px radius for cursor highlight
  const rawDistance = useTransform([mouseX, mouseY], ([mx, my]) => {
    if (searchActive) return 9999; // bypass cursor lighting during active searches
    const dx = mx - item.x;
    const dy = my - item.y;
    return Math.sqrt(dx * dx + dy * dy);
  });

  // Interpolate opacity/brightness relative to distance
  // Foreground layers get full dynamic brightness, background layers are slightly illuminated
  const brightnessMap = item.z === 0 ? [hoverBrightness, 1.0] : item.z === 1 ? [1.12, 1.0] : [1.05, 1.0];
  const opacityMap = item.z === 0 ? [1.0, 0.85] : item.z === 1 ? [0.75, 0.5] : [0.45, 0.28];

  const derivedBrightness = useTransform(rawDistance, [0, 240], brightnessMap);
  const derivedOpacity = useTransform(rawDistance, [0, 240], opacityMap);

  // Transform brightness motion value into a valid CSS filter string
  const filterString = useTransform(derivedBrightness, (val) => `brightness(${val})`);

  // Fallback constant motion value if mouseParallax or cursorLighting is not running
  const staticOpacity = item.z === 0 ? 0.9 : item.z === 1 ? 0.55 : 0.32;

  // Stagger delay based on index hash
  const initialDelay = (item.name.charCodeAt(0) % 10) * 0.08;

  const itemState = {
    isHovered,
    isHighlighted: item.isHighlighted,
    isMatched
  };

  return (
    <motion.div
      className="absolute pointer-events-auto origin-center select-none"
      style={{
        left: item.x,
        top: item.y,
        zIndex: 50 - item.z * 15 + (isHovered ? 100 : 0)
      }}
      initial={{ opacity: 0, y: item.y + 16, scale: 0.92 }}
      animate={{ 
        opacity: 1, 
        y: item.y, 
        scale: searchActive && isMatched ? 1.15 : 1.0 
      }}
      transition={{
        type: "spring",
        stiffness: 110,
        damping: 14,
        delay: initialDelay
      }}
    >
      <motion.div
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        style={{
          opacity: searchActive ? undefined : (mouseParallax ? derivedOpacity : staticOpacity),
          filter: searchActive ? undefined : (mouseParallax ? filterString : undefined),
          fontSize: `${item.fontSize}px`,
          rotate: `${item.rotation}deg`,
          fontWeight: fontWeight ?? (item.isHighlighted ? 800 : 400),
          cursor: "pointer",
          willChange: "transform, opacity",
          ...inlineStyles
        }}
        animate={{
          scale: isHovered ? hoverScale : 1.0,
          filter: isHovered ? `brightness(${hoverBrightness})` : `brightness(1.0)`,
          textDecoration: isHovered ? "underline" : "none",
        }}
        transition={{
          type: "spring",
          stiffness: 160,
          damping: 12
        }}
        className={`tracking-tight whitespace-nowrap transition-colors duration-200 ${fontClass} ${getColors()}`}
      >
        {renderName ? renderName(item.name, 0, itemState) : item.name}
      </motion.div>
    </motion.div>
  );
}

import React from "react";

interface BackgroundLayerProps {
  type: "solid" | "noise" | "paper" | "grid" | "gradient" | "texture";
  colorMode: "light" | "dark";
}

export function BackgroundLayer({ type, colorMode }: BackgroundLayerProps) {
  const isDark = colorMode === "dark";

  // Base theme variables
  const bgBase = isDark ? "bg-[#0B0B0B]" : "bg-[#F4F1E8]";
  const textColor = isDark ? "text-white/10" : "text-black/8";

  return (
    <div className={`absolute inset-0 z-0 overflow-hidden select-none pointer-events-none ${bgBase}`}>
      {/* Noise Texture Layer */}
      {(type === "noise" || type === "texture" || type === "paper") && (
        <div 
          className="absolute inset-0 mix-blend-overlay opacity-[0.035]"
          style={{
            backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.8' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")`
          }}
        />
      )}

      {/* Grid Pattern Layer */}
      {(type === "grid" || type === "texture") && (
        <div 
          className={`absolute inset-0 opacity-[0.25] ${
            isDark 
              ? "[background-image:linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)]"
              : "[background-image:linear-gradient(rgba(0,0,0,0.04)_1px,transparent_1px),linear-gradient(90deg,rgba(0,0,0,0.04)_1px,transparent_1px)]"
          } [background-size:60px_60px]`}
        />
      )}

      {/* Paper Fibers Texture */}
      {type === "paper" && (
        <>
          <div className="absolute inset-0 opacity-[0.04] bg-[radial-gradient(circle,currentColor_1px,transparent_1px)] [background-size:24px_24px] text-neutral-500" />
          <div className="absolute inset-0 opacity-[0.02] bg-[linear-gradient(90deg,rgba(0,0,0,0.1)_1px,transparent_1px),linear-gradient(rgba(0,0,0,0.1)_1px,transparent_1px)] [background-size:8px_8px]" />
        </>
      )}

      {/* Modern Blurred Mesh Gradients */}
      {type === "gradient" && (
        <div className="absolute -inset-[40px] opacity-[0.45] blur-[130px] overflow-hidden">
          {isDark ? (
            <>
              {/* Deep charcoal, slate, and hint of aubergine */}
              <div className="absolute top-[10%] left-[20%] w-[55%] h-[55%] rounded-full bg-[#18151A]" />
              <div className="absolute bottom-[15%] right-[10%] w-[60%] h-[60%] rounded-full bg-[#11161B]" />
              <div className="absolute top-[40%] right-[30%] w-[45%] h-[45%] rounded-full bg-[#141414]" />
            </>
          ) : (
            <>
              {/* Soft warm tan, oatmeal, and eggshell cream */}
              <div className="absolute top-[10%] left-[20%] w-[60%] h-[60%] rounded-full bg-[#ECE7DC]" />
              <div className="absolute bottom-[10%] right-[10%] w-[55%] h-[55%] rounded-full bg-[#EAE3D5]" />
              <div className="absolute top-[35%] right-[25%] w-[50%] h-[50%] rounded-full bg-[#F3ECE0]" />
            </>
          )}
        </div>
      )}

      {/* Soft Vignette Overlay */}
      <div 
        className={`absolute inset-0 ${
          isDark 
            ? "bg-[radial-gradient(circle_at_center,transparent_20%,rgba(9,9,9,0.3)_100%)]" 
            : "bg-[radial-gradient(circle_at_center,transparent_20%,rgba(244,241,232,0.25)_100%)]"
        }`}
      />
    </div>
  );
}

export interface PositionedName {
  id: string;
  name: string;
  x: number; // absolute px
  y: number; // absolute px
  z: number; // depth layer index (0: foreground, 1: midground, 2: background)
  fontSize: number;
  rotation: number;
  isHighlighted: boolean;
}

// Seedable linear congruential generator for stable, deterministic layout
export function createRandom(seed: number) {
  let s = seed;
  return () => {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

export function generateLayout(
  names: string[],
  variant: "constellation" | "grid" | "helical",
  width: number,
  height: number,
  density: number = 2, // 1: sparse, 2: balanced, 3: dense
  spacing: number = 1.0,
  fontScale: number = 1.0,
  highlightedNames: string[] = []
): PositionedName[] {
  if (width <= 0 || height <= 0 || names.length === 0) return [];

  const rand = createRandom(42); // fixed seed for layout stability
  const densityMultiplier = density === 1 ? 0.4 : density === 2 ? 0.7 : 1.1;
  const maxItems = Math.min(names.length, Math.floor(250 * densityMultiplier));
  const selectedNames = names.slice(0, maxItems);

  const highlightedSet = new Set(
    highlightedNames.map((n) => n.toLowerCase())
  );

  const items: PositionedName[] = [];

  // Helper to approximate text width/height
  const getBox = (name: string, fontSize: number) => {
    // Width factor of 0.6 per char for typical sans-serif
    return {
      w: name.length * fontSize * 0.55,
      h: fontSize * 1.3,
    };
  };

  if (variant === "constellation") {
    // 1. Distribute names into depth layers
    // Foreground (15%), Midground (35%), Background (50%)
    for (let i = 0; i < selectedNames.length; i++) {
      const name = selectedNames[i];
      const isHighlighted = highlightedSet.has(name.toLowerCase());

      let z = 2; // default background
      const layerRoll = rand();
      if (isHighlighted || layerRoll < 0.15) {
        z = 0; // foreground
      } else if (layerRoll < 0.5) {
        z = 1; // midground
      }

      // Base font size dependent on layer
      let baseSize = 13;
      if (z === 0) baseSize = isHighlighted ? 48 : 34;
      else if (z === 1) baseSize = 22;
      else baseSize = 14;

      const fontSize = Math.round(baseSize * fontScale);
      const rotation = (rand() - 0.5) * 8; // light rotation

      // Place initial random position focused around center
      const r = Math.min(width, height) * 0.4 * Math.sqrt(rand());
      const angle = rand() * Math.PI * 2;
      const x = width / 2 + Math.cos(angle) * r;
      const y = height / 2 + Math.sin(angle) * r;

      items.push({
        id: `${name}-${i}`,
        name,
        x,
        y,
        z,
        fontSize,
        rotation,
        isHighlighted,
      });
    }

    // 2. Collision avoidance relaxation (25 iterations)
    const basePadding = 18 * spacing;
    for (let iter = 0; iter < 25; iter++) {
      for (let i = 0; i < items.length; i++) {
        const itemA = items[i];
        const boxA = getBox(itemA.name, itemA.fontSize);

        for (let j = i + 1; j < items.length; j++) {
          const itemB = items[j];
          // Only push away significantly if they are on same or adjacent layer
          if (Math.abs(itemA.z - itemB.z) > 1) continue;

          const boxB = getBox(itemB.name, itemB.fontSize);

          const dx = itemB.x - itemA.x;
          const dy = itemB.y - itemA.y;

          const minDistanceX = (boxA.w + boxB.w) / 2 + basePadding;
          const minDistanceY = (boxA.h + boxB.h) / 2 + basePadding;

          const overlapX = minDistanceX - Math.abs(dx);
          const overlapY = minDistanceY - Math.abs(dy);

          if (overlapX > 0 && overlapY > 0) {
            // Push along the vector with smaller overlap to minimize movement distance
            const pushX = Math.sign(dx || 0.1) * overlapX * 0.45;
            const pushY = Math.sign(dy || 0.1) * overlapY * 0.45;

            if (overlapX < overlapY) {
              itemA.x -= pushX;
              itemB.x += pushX;
            } else {
              itemA.y -= pushY;
              itemB.y += pushY;
            }
          }
        }

        // Apply a gentle boundary correction and center gravity
        const borderX = width * 0.05;
        const borderY = height * 0.05;
        itemA.x = Math.max(borderX, Math.min(width - borderX - boxA.w, itemA.x));
        itemA.y = Math.max(borderY, Math.min(height - borderY - boxA.h, itemA.y));
      }
    }
  } else if (variant === "grid") {
    // Balanced masonry column layout
    const colCount = Math.max(3, Math.min(8, Math.floor(width / (220 * spacing))));
    const colWidths = width / colCount;

    // Track vertical usage per column
    const colHeights = Array(colCount).fill(height * 0.06);

    for (let i = 0; i < selectedNames.length; i++) {
      const name = selectedNames[i];
      const isHighlighted = highlightedSet.has(name.toLowerCase());

      // Assign to the shortest column
      let colIndex = 0;
      let minH = colHeights[0];
      for (let c = 1; c < colCount; c++) {
        if (colHeights[c] < minH) {
          minH = colHeights[c];
          colIndex = c;
        }
      }

      // Determine layer and font sizes
      let z = 2; // background
      const roll = rand();
      if (isHighlighted || roll < 0.12) z = 0;
      else if (roll < 0.4) z = 1;

      let baseSize = 14;
      if (z === 0) baseSize = isHighlighted ? 44 : 32;
      else if (z === 1) baseSize = 20;

      const fontSize = Math.round(baseSize * fontScale);
      const box = getBox(name, fontSize);

      // Align columns with natural shifts
      const shiftX = (rand() - 0.5) * colWidths * 0.3;
      const x = colIndex * colWidths + colWidths / 2 + shiftX - box.w / 2;
      const y = colHeights[colIndex];

      const rotation = (rand() - 0.5) * 5; // light clean rotation

      items.push({
        id: `${name}-${i}`,
        name,
        x,
        y,
        z,
        fontSize,
        rotation,
        isHighlighted,
      });

      // Update vertical height for this column
      colHeights[colIndex] += box.h + (35 * spacing * (0.8 + rand() * 0.4));

      // Wrap back up if the column height overflows the layout container
      if (colHeights[colIndex] > height * 0.9) {
        colHeights[colIndex] = height * (0.06 + rand() * 0.1);
      }
    }
  } else if (variant === "helical") {
    // 3D Helix coordinate distribution
    const helixRadius = Math.min(width, height) * 0.36;
    const spiralTurns = 3;
    const angleOffset = Math.PI * 0.3;

    for (let i = 0; i < selectedNames.length; i++) {
      const name = selectedNames[i];
      const isHighlighted = highlightedSet.has(name.toLowerCase());

      const progress = i / selectedNames.length;
      const theta = progress * spiralTurns * Math.PI * 2 + angleOffset;

      // Spiral equations
      const r = helixRadius * (0.4 + 0.6 * progress);
      const x = width / 2 + Math.cos(theta) * r;
      const y = height * (0.1 + progress * 0.8);

      // Distribute to depth z levels based on helix theta position
      // Foreground: Front-facing quadrant of helix
      const cosTheta = Math.cos(theta);
      let z = 1; // midground
      if (cosTheta > 0.4) z = 0; // foreground
      else if (cosTheta < -0.3) z = 2; // background

      let baseSize = 13;
      if (z === 0) baseSize = isHighlighted ? 46 : 30;
      else if (z === 1) baseSize = 20;

      const fontSize = Math.round(baseSize * fontScale);
      const rotation = (rand() - 0.5) * 6;

      items.push({
        id: `${name}-${i}`,
        name,
        x: x - (name.length * fontSize * 0.25), // dynamic center correction
        y,
        z,
        fontSize,
        rotation,
        isHighlighted,
      });
    }
  }

  return items;
}
